Write-Host "PURGING JavaScript/TypeScript Stack..." -ForegroundColor Red; $jstsPackages = @("typescript", "ts-node", "tsx", "@swc/core", "@swc/cli", "esbuild", "webpack", "webpack-cli", "vite", "rollup", "parcel", "babel-cli", "@babel/core", "@babel/preset-env", "@babel/preset-typescript", "eslint", "@typescript-eslint/eslint-plugin", "@typescript-eslint/parser", "prettier", "jest", "@jest/cli", "mocha", "chai", "vitest", "nodemon", "ts-node-dev", "concurrently", "npm-run-all", "cross-env", "rimraf", "cpx", "onchange", "chokidar-cli", "typedoc", "jsdoc", "@types/node", "tsconfig-paths", "typescript-json-schema", "source-map-explorer", "madge", "depcheck", "npm-check-updates", "audit-ci", "husky", "lint-staged", "yargs", "commander", "inquirer", "chalk", "ora", "dotenv-cli", "pm2", "http-server", "live-server", "json-server", "cors", "yarn", "pnpm"); foreach($pkg in $jstsPackages) { npm uninstall -g $pkg --force --silent 2>$null; yarn global remove $pkg --silent 2>$null; pnpm remove -g $pkg --silent 2>$null; bun remove -g $pkg --silent 2>$null }; $wingetPackages = @("OpenJS.NodeJS", "Yarn.Yarn", "pnpm.pnpm", "Deno.Deno", "oven-sh.bun"); foreach($pkg in $wingetPackages) { winget uninstall --id $pkg --silent --force 2>$null }; npm cache clean --force 2>$null; yarn cache clean --force 2>$null; pnpm store prune --force 2>$null; $dirsToRemove = @("$env:USERPROFILE\js-ts-dev", "$env:USERPROFILE\.npm", "$env:USERPROFILE\.yarn", "$env:USERPROFILE\.pnpm-store", "$env:USERPROFILE\.cache", "$env:APPDATA\npm", "$env:LOCALAPPDATA\npm-cache", "$env:TEMP\npm-*", "$env:USERPROFILE\tsconfig.json", "$env:USERPROFILE\.prettierrc"); foreach($dir in $dirsToRemove) { if(Test-Path $dir) { Remove-Item $dir -Recurse -Force -ErrorAction SilentlyContinue } }; Get-ChildItem -Path $env:USERPROFILE -Name "node_modules" -Recurse -Directory -Force -ErrorAction SilentlyContinue | ForEach-Object { Remove-Item $_.FullName -Recurse -Force -ErrorAction SilentlyContinue }; $envVars = @("NODE_PATH", "NPM_CONFIG_PREFIX", "YARN_GLOBAL_FOLDER", "PNPM_HOME", "BUN_INSTALL", "DENO_DIR"); foreach($envVar in $envVars) { [Environment]::SetEnvironmentVariable($envVar, $null, "User"); [Environment]::SetEnvironmentVariable($envVar, $null, "Machine") }; $currentPath = [Environment]::GetEnvironmentVariable("PATH", "Machine"); $cleanPath = ($currentPath -split ';' | Where-Object { $_ -notmatch "nodejs|npm|yarn|pnpm|bun|deno" }) -join ';'; [Environment]::SetEnvironmentVariable("PATH", $cleanPath, "Machine"); $currentUserPath = [Environment]::GetEnvironmentVariable("PATH", "User"); $cleanUserPath = ($currentUserPath -split ';' | Where-Object { $_ -notmatch "nodejs|npm|yarn|pnpm|bun|deno" }) -join ';'; [Environment]::SetEnvironmentVariable("PATH", $cleanUserPath, "User"); Write-Host "JS/TS Stack PURGED!" -ForegroundColor Green; if(Get-Command node -ErrorAction SilentlyContinue) { Write-Host "WARNING: Node still detected" -ForegroundColor Red } else { Write-Host "Node: Successfully removed" -ForegroundColor Green }; if(Get-Command tsc -ErrorAction SilentlyContinue) { Write-Host "WARNING: TypeScript still detected" -ForegroundColor Red } else { Write-Host "TypeScript: Successfully removed" -ForegroundColor Green }
